import{_ as p,c as s,o as l,aK as a}from"./chunks/framework.gpVTZwhR.js";const h=JSON.parse('{"title":"07_Asleep和Sleepy的区别？","description":"","frontmatter":{},"headers":[],"relativePath":"gaozhong/03_英语/02_自己总结/02_单词句子语法辨析/07_Asleep和Sleepy的区别？.md","filePath":"gaozhong/03_英语/02_自己总结/02_单词句子语法辨析/07_Asleep和Sleepy的区别？.md","lastUpdated":1741447220000}'),t={name:"gaozhong/03_英语/02_自己总结/02_单词句子语法辨析/07_Asleep和Sleepy的区别？.md"};function _(o,e,n,r,c,d){return l(),s("div",null,e[0]||(e[0]=[a('<h1 id="_07-asleep和sleepy的区别" tabindex="-1">07_Asleep和Sleepy的区别？ <a class="header-anchor" href="#_07-asleep和sleepy的区别" aria-label="Permalink to &quot;07_Asleep和Sleepy的区别？&quot;">​</a></h1><p>sleepy，asleep这两个形容词均含有“欲睡的”之意。</p><p>区别在于：</p><p><strong>1、asleep的意思是“睡着”,而sleepy的意思是“想睡”。</strong></p><p>例如：The baby fell asleep; and I feel sleepy.孩子睡着了,我也犯困了。</p><p><strong>2、asleep一般用作表语,意为“睡着的”,强调状态；它不能用very修饰,只可用much,fast,sound等词修饰。有时也可作后置定语。</strong></p><p>例如：When he came home last night ,we were all asleep.他昨晚回家时,我们都睡着了。</p><p>The boy asleep is his son.正在睡觉的那个男孩是他儿子。</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p><span class="text-red">fall asleep</span> 是动词词组， 意思是”入睡“，表示刚刚睡觉时的状态。</p></div><p><strong>3、sleepy：既可作表语,亦可作前置定语。用作前者,意为“困乏的,想睡觉的”,用作后者,意为“贪睡的,好睡的”。</strong></p><p>例如：I felt sleepy all day.我整天都犯困。</p>',11)]))}const y=p(t,[["render",_]]);export{h as __pageData,y as default};
